714 /// %y2 = extractelement <4 x i8> %y, i32 2
715 /// %x0x0 = mul i8 %x0, %x0
716 /// %x3x3 = mul i8 %x3, %x3
717 /// %y1y1 = mul i8 %y1, %y1
718 /// %y2y2 = mul i8 %y2, %y2
719 /// %ins1 = insertelement <4 x i8> poison, i8 %x0x0, i32 0
720 /// %ins2 = insertelement <4 x i8> %ins1, i8 %x3x3, i32 1
721 /// %ins3 = insertelement <4 x i8> %ins2, i8 %y1y1, i32 2
722 /// %ins4 = insertelement <4 x i8> %ins3, i8 %y2y2, i32 3
723 /// ret <4 x i8> %ins4
724 /// can be transformed into:
725 /// %1 = shufflevector <4 x i8> %x, <4 x i8> %y, <4 x i32> <i32 0, i32 3, i32 5,
726 ///                                                         i32 6>
727 /// %2 = mul <4 x i8> %1, %1
728 /// ret <4 x i8> %2
