730 /// TODO: Can we split off and reuse the shuffle mask detection from
731 /// ShuffleVectorInst/getShuffleCost?
732 static std::optional<TargetTransformInfo::ShuffleKind>
733 isFixedVectorShuffle(ArrayRef<Value *> VL, SmallVectorImpl<int> &Mask,
734                      AssumptionCache *AC) {
735   const auto *It = find_if(VL, IsaPred<ExtractElementInst>);
736   if (It == VL.end())
737     return std::nullopt;
738   unsigned Size =
739       std::accumulate(VL.begin(), VL.end(), 0u, [](unsigned S, Value *V) {
740         auto *EI = dyn_cast<ExtractElementInst>(V);
741         if (!EI)
742           return S;
743         auto *VTy = dyn_cast<FixedVectorType>(EI->getVectorOperandType());
744         if (!VTy)
745           return S;
746         return std::max(S, VTy->getNumElements());
747       });
748 
749   Value *Vec1 = nullptr;
750   Value *Vec2 = nullptr;
751   bool HasNonUndefVec = any_of(VL, [&](Value *V) {
752     auto *EE = dyn_cast<ExtractElementInst>(V);
753     if (!EE)
754       return false;
755     Value *Vec = EE->getVectorOperand();
756     if (isa<UndefValue>(Vec))
757       return false;
758     return isGuaranteedNotToBePoison(Vec, AC);
759   });
760   enum ShuffleMode { Unknown, Select, Permute };
761   ShuffleMode CommonShuffleMode = Unknown;
762   Mask.assign(VL.size(), PoisonMaskElem);
763   for (unsigned I = 0, E = VL.size(); I < E; ++I) {
764     // Undef can be represented as an undef element in a vector.
765     if (isa<UndefValue>(VL[I]))
766       continue;
767     auto *EI = cast<ExtractElementInst>(VL[I]);
768     if (isa<ScalableVectorType>(EI->getVectorOperandType()))
769       return std::nullopt;
770     auto *Vec = EI->getVectorOperand();
771     // We can extractelement from undef or poison vector.
772     if (isUndefVector</*isPoisonOnly=*/true>(Vec).all())
773       continue;
774     // All vector operands must have the same number of vector elements.
775     if (isa<UndefValue>(Vec)) {
776       Mask[I] = I;
777     } else {
778       if (isa<UndefValue>(EI->getIndexOperand()))
779         continue;
780       auto *Idx = dyn_cast<ConstantInt>(EI->getIndexOperand());
781       if (!Idx)
782         return std::nullopt;
783       // Undefined behavior if Idx is negative or >= Size.
784       if (Idx->getValue().uge(Size))
785         continue;
786       unsigned IntIdx = Idx->getValue().getZExtValue();
787       Mask[I] = IntIdx;
788     }
789     if (isUndefVector(Vec).all() && HasNonUndefVec)
790       continue;
791     // For correct shuffling we have to have at most 2 different vector operands
792     // in all extractelement instructions.
793     if (!Vec1 || Vec1 == Vec) {
794       Vec1 = Vec;
795     } else if (!Vec2 || Vec2 == Vec) {
796       Vec2 = Vec;
797       Mask[I] += Size;
798     } else {
799       return std::nullopt;
800     }
801     if (CommonShuffleMode == Permute)
802       continue;
803     // If the extract index is not the same as the operation number, it is a
804     // permutation.
805     if (Mask[I] % Size != I) {
806       CommonShuffleMode = Permute;
807       continue;
808     }
809     CommonShuffleMode = Select;
810   }
811   // If we're not crossing lanes in different vectors, consider it as blending.
812   if (CommonShuffleMode == Select && Vec2)
813     return TargetTransformInfo::SK_Select;
814   // If Vec2 was never used, we have a permutation of a single vector, otherwise
815   // we have permutation of 2 vectors.
816   return Vec2 ? TargetTransformInfo::SK_PermuteTwoSrc
817               : TargetTransformInfo::SK_PermuteSingleSrc;
