1105 /// Main data required for vectorization of instructions.
1106 class InstructionsState {
1107   /// MainOp and AltOp are primarily determined by getSameOpcode. Currently,
1108   /// only BinaryOperator, CastInst, and CmpInst support alternate instructions
1109   /// (i.e., AltOp is not equal to MainOp; this can be checked using
1110   /// isAltShuffle).
1111   /// A rare exception is TrySplitNode, where the InstructionsState is derived
1112   /// from getMainAltOpsNoStateVL.
1113   /// For those InstructionsState that use alternate instructions, the resulting
1114   /// vectorized output ultimately comes from a shufflevector. For example,
1115   /// given a vector list (VL):
1116   /// VL[0] = add i32 a, e
1117   /// VL[1] = sub i32 b, f
1118   /// VL[2] = add i32 c, g
1119   /// VL[3] = sub i32 d, h
1120   /// The vectorized result would be:
1121   /// intermediated_0 = add <4 x i32> <a, b, c, d>, <e, f, g, h>
1122   /// intermediated_1 = sub <4 x i32> <a, b, c, d>, <e, f, g, h>
1123   /// result = shufflevector <4 x i32> intermediated_0,
1124   ///                        <4 x i32> intermediated_1,
1125   ///                        <4 x i32> <i32 0, i32 5, i32 2, i32 7>
1126   /// Since shufflevector is used in the final result, when calculating the cost
1127   /// (getEntryCost), we must account for the usage of shufflevector in
1128   /// GetVectorCost.
1129   Instruction *MainOp = nullptr;
1130   Instruction *AltOp = nullptr;
1131 
1132 public:
1133   Instruction *getMainOp() const {
1134     assert(valid() && "InstructionsState is invalid.");
1135     return MainOp;
1136   }
1137 
1138   Instruction *getAltOp() const {
1139     assert(valid() && "InstructionsState is invalid.");
1140     return AltOp;
1141   }
