1543 /// Shuffles \p Mask in accordance with the given \p SubMask.
1544 /// \param ExtendingManyInputs Supports reshuffling of the mask with not only
1545 /// one but two input vectors.
1546 static void addMask(SmallVectorImpl<int> &Mask, ArrayRef<int> SubMask,
1547                     bool ExtendingManyInputs = false) {
