2592         int SplatScore = getSplatScore(Lane, OpIdx, Idx, UsedLanes);
2593         if (Score <= -SplatScore) {
2594           // Failed score.
2595           Score = 0;
2596         } else {
2597           Score += SplatScore;
2598           // Scale score to see the difference between different operands
2599           // and similar operands but all vectorized/not all vectorized
2600           // uses. It does not affect actual selection of the best
2601           // compatible operand in general, just allows to select the
2602           // operand with all vectorized uses.
2603           Score *= ScoreScaleFactor;
2604           Score += getExternalUseScore(Lane, OpIdx, Idx);
2605           IsUsed = true;
