2619     // Search all operands in Ops[*][Lane] for the one that matches best
2620     // Ops[OpIdx][LastLane] and return its opreand index.
2621     // If no good match can be found, return std::nullopt.
2622     std::optional<unsigned>
2623     getBestOperand(unsigned OpIdx, int Lane, int LastLane,
2624                    ArrayRef<ReorderingMode> ReorderingModes,
2625                    ArrayRef<Value *> MainAltOps,
2626                    const SmallBitVector &UsedLanes) {
2627       unsigned NumOperands = getNumOperands();
2628 
2629       // The operand of the previous lane at OpIdx.
2630       Value *OpLastLane = getData(OpIdx, LastLane).V;
2631 
2632       // Our strategy mode for OpIdx.
2633       ReorderingMode RMode = ReorderingModes[OpIdx];
2634       if (RMode == ReorderingMode::Failed)
2635         return std::nullopt;
2636 
2637       // The linearized opcode of the operand at OpIdx, Lane.
2638       bool OpIdxAPO = getData(OpIdx, Lane).APO;
2639 
2640       // The best operand index and its score.
2641       // Sometimes we have more than one option (e.g., Opcode and Undefs), so we
2642       // are using the score to differentiate between the two.
2643       struct BestOpData {
2644         std::optional<unsigned> Idx;
2645         unsigned Score = 0;
2646       } BestOp;
2647       BestOp.Score =
2648           BestScoresPerLanes.try_emplace(std::make_pair(OpIdx, Lane), 0)
2649               .first->second;
2650 
2651       // Track if the operand must be marked as used. If the operand is set to
2652       // Score 1 explicitly (because of non power-of-2 unique scalars, we may
2653       // want to reestimate the operands again on the following iterations).
2654       bool IsUsed = RMode == ReorderingMode::Splat ||
2655                     RMode == ReorderingMode::Constant ||
2656                     RMode == ReorderingMode::Load;
2657       // Iterate through all unused operands and look for the best.
2658       for (unsigned Idx = 0; Idx != NumOperands; ++Idx) {
2659         // Get the operand at Idx and Lane.
2660         OperandData &OpData = getData(Idx, Lane);
2661         Value *Op = OpData.V;
2662         bool OpAPO = OpData.APO;
2663 
2664         // Skip already selected operands.
2665         if (OpData.IsUsed)
2666           continue;
2667 
2668         // Skip if we are trying to move the operand to a position with a
2669         // different opcode in the linearized tree form. This would break the
2670         // semantics.
2671         if (OpAPO != OpIdxAPO)
2672           continue;
2673 
2674         // Look for an operand that matches the current mode.
2675         switch (RMode) {
2676         case ReorderingMode::Load:
2677         case ReorderingMode::Opcode: {
2678           bool LeftToRight = Lane > LastLane;
2679           Value *OpLeft = (LeftToRight) ? OpLastLane : Op;
2680           Value *OpRight = (LeftToRight) ? Op : OpLastLane;
2681           int Score = getLookAheadScore(OpLeft, OpRight, MainAltOps, Lane,
2682                                         OpIdx, Idx, IsUsed, UsedLanes);
2683           if (Score > static_cast<int>(BestOp.Score) ||
2684               (Score > 0 && Score == static_cast<int>(BestOp.Score) &&
2685                Idx == OpIdx)) {
2686             BestOp.Idx = Idx;
2687             BestOp.Score = Score;
2688             BestScoresPerLanes[std::make_pair(OpIdx, Lane)] = Score;
2689           }
2690           break;
2691         }
2692         case ReorderingMode::Constant:
2693           if (isa<Constant>(Op) ||
2694               (!BestOp.Score && L && L->isLoopInvariant(Op))) {
2695             BestOp.Idx = Idx;
2696             if (isa<Constant>(Op)) {
2697               BestOp.Score = LookAheadHeuristics::ScoreConstants;
2698               BestScoresPerLanes[std::make_pair(OpIdx, Lane)] =
2699                   LookAheadHeuristics::ScoreConstants;
2700             }
2701             if (isa<UndefValue>(Op) || !isa<Constant>(Op))
2702               IsUsed = false;
2703           }
2704           break;
2705         case ReorderingMode::Splat:
2706           if (Op == OpLastLane || (!BestOp.Score && isa<Constant>(Op))) {
2707             IsUsed = Op == OpLastLane;
2708             if (Op == OpLastLane) {
2709               BestOp.Score = LookAheadHeuristics::ScoreSplat;
2710               BestScoresPerLanes[std::make_pair(OpIdx, Lane)] =
2711                   LookAheadHeuristics::ScoreSplat;
2712             }
2713             BestOp.Idx = Idx;
2714           }
2715           break;
2716         case ReorderingMode::Failed:
2717           llvm_unreachable("Not expected Failed reordering mode.");
2718         }
2719       }
2720 
2721       if (BestOp.Idx) {
2722         getData(*BestOp.Idx, Lane).IsUsed = IsUsed;
2723         return BestOp.Idx;
2724       }
2725       // If we could not find a good match return std::nullopt.
2726       return std::nullopt;
2727     }
