3025     // Performs operand reordering for 2 or more operands.
3026     // The original operands are in OrigOps[OpIdx][Lane].
3027     // The reordered operands are returned in 'SortedOps[OpIdx][Lane]'.
3028     void reorder() {
3029       unsigned NumOperands = getNumOperands();
3030       unsigned NumLanes = getNumLanes();
3031       // Each operand has its own mode. We are using this mode to help us select
3032       // the instructions for each lane, so that they match best with the ones
3033       // we have selected so far.
3034       SmallVector<ReorderingMode, 2> ReorderingModes(NumOperands);
3035 
3036       // This is a greedy single-pass algorithm. We are going over each lane
3037       // once and deciding on the best order right away with no back-tracking.
3038       // However, in order to increase its effectiveness, we start with the lane
3039       // that has operands that can move the least. For example, given the
3040       // following lanes:
3041       //  Lane 0 : A[0] = B[0] + C[0]   // Visited 3rd
3042       //  Lane 1 : A[1] = C[1] - B[1]   // Visited 1st
3043       //  Lane 2 : A[2] = B[2] + C[2]   // Visited 2nd
3044       //  Lane 3 : A[3] = C[3] - B[3]   // Visited 4th
3045       // we will start at Lane 1, since the operands of the subtraction cannot
3046       // be reordered. Then we will visit the rest of the lanes in a circular
3047       // fashion. That is, Lanes 2, then Lane 0, and finally Lane 3.
3048 
3049       // Find the first lane that we will start our search from.
3050       unsigned FirstLane = getBestLaneToStartReordering();
3051 
3052       // Initialize the modes.
3053       for (unsigned OpIdx = 0; OpIdx != NumOperands; ++OpIdx) {
3054         Value *OpLane0 = getValue(OpIdx, FirstLane);
3055         // Keep track if we have instructions with all the same opcode on one
3056         // side.
3057         if (auto *OpILane0 = dyn_cast<Instruction>(OpLane0)) {
3058           // Check if OpLane0 should be broadcast.
3059           if (shouldBroadcast(OpLane0, OpIdx, FirstLane) ||
3060               !canBeVectorized(OpILane0, OpIdx, FirstLane))
3061             ReorderingModes[OpIdx] = ReorderingMode::Splat;
3062           else if (isa<LoadInst>(OpILane0))
3063             ReorderingModes[OpIdx] = ReorderingMode::Load;
3064           else
3065             ReorderingModes[OpIdx] = ReorderingMode::Opcode;
3066         } else if (isa<Constant>(OpLane0)) {
3067           ReorderingModes[OpIdx] = ReorderingMode::Constant;
3068         } else if (isa<Argument>(OpLane0)) {
3069           // Our best hope is a Splat. It may save some cost in some cases.
3070           ReorderingModes[OpIdx] = ReorderingMode::Splat;
3071         } else {
3072           llvm_unreachable("Unexpected value kind.");
3073         }
3074       }
3075 
3076       // Check that we don't have same operands. No need to reorder if operands
3077       // are just perfect diamond or shuffled diamond match. Do not do it only
3078       // for possible broadcasts or non-power of 2 number of scalars (just for
3079       // now).
3080       auto &&SkipReordering = [this]() {
3081         SmallPtrSet<Value *, 4> UniqueValues;
3082         ArrayRef<OperandData> Op0 = OpsVec.front();
3083         for (const OperandData &Data : Op0)
3084           UniqueValues.insert(Data.V);
3085         for (ArrayRef<OperandData> Op :
3086              ArrayRef(OpsVec).slice(1, getNumOperands() - 1)) {
3087           if (any_of(Op, [&UniqueValues](const OperandData &Data) {
3088                 return !UniqueValues.contains(Data.V);
3089               }))
3090             return false;
3091         }
3092         // TODO: Check if we can remove a check for non-power-2 number of
3093         // scalars after full support of non-power-2 vectorization.
3094         return UniqueValues.size() != 2 &&
3095                hasFullVectorsOrPowerOf2(*R.TTI, Op0.front().V->getType(),
3096                                         UniqueValues.size());
3097       };
3098 
3099       // If the initial strategy fails for any of the operand indexes, then we
3100       // perform reordering again in a second pass. This helps avoid assigning
3101       // high priority to the failed strategy, and should improve reordering for
3102       // the non-failed operand indexes.
3103       for (int Pass = 0; Pass != 2; ++Pass) {
3104         // Check if no need to reorder operands since they're are perfect or
3105         // shuffled diamond match.
3106         // Need to do it to avoid extra external use cost counting for
3107         // shuffled matches, which may cause regressions.
3108         if (SkipReordering())
3109           break;
3110         // Skip the second pass if the first pass did not fail.
3111         bool StrategyFailed = false;
