3115         // rest of the lanes. We are visiting the nodes in a circular fashion,
3116         // using FirstLane as the center point and increasing the radius
3117         // distance.
3118         SmallVector<SmallVector<Value *, 2>> MainAltOps(NumOperands);
3119         for (unsigned I = 0; I < NumOperands; ++I)
