1206             getOpcode() == Instruction::FCmp) &&
1207            getAltOpcode() == getOpcode();
1208   }
1209 
1210   /// Checks if the current state is valid, i.e. has non-null MainOp
1211   bool valid() const { return MainOp && AltOp; }
1212 
1213   explicit operator bool() const { return valid(); }
1214 
1215   InstructionsState() = delete;
1216   InstructionsState(Instruction *MainOp, Instruction *AltOp)
1217       : MainOp(MainOp), AltOp(AltOp) {}
1218   static InstructionsState invalid() { return {nullptr, nullptr}; }
1219 };
1220 
1221 std::pair<Instruction *, SmallVector<Value *>>
1222 convertTo(Instruction *I, const InstructionsState &S) {
1223   Instruction *SelectedOp = S.getMatchingMainOpOrAltOp(I);
1224   assert(SelectedOp && "Cannot convert the instruction.");
1225   if (I->isBinaryOp()) {
1226     BinOpSameOpcodeHelper Converter(I);
1227     return std::make_pair(SelectedOp, Converter.getOperand(SelectedOp));
1228   }
1229   return std::make_pair(SelectedOp, SmallVector<Value *>(I->operands()));
1230 }
1231 
1232 } // end anonymous namespace
