1237 /// Find an instruction with a specific opcode in VL.
1238 /// \param VL Array of values to search through. Must contain only Instructions
1239 ///           and PoisonValues.
1240 /// \param Opcode The instruction opcode to search for
1241 /// \returns
1242 /// - The first instruction found with matching opcode
1243 /// - nullptr if no matching instruction is found
1244 Instruction *findInstructionWithOpcode(ArrayRef<Value *> VL, unsigned Opcode) {
1245   for (Value *V : VL) {
1246     if (isa<PoisonValue>(V))
1247       continue;
1248     assert(isa<Instruction>(V) && "Only accepts PoisonValue and Instruction.");
1249     auto *Inst = cast<Instruction>(V);
1250     if (Inst->getOpcode() == Opcode)
1251       return Inst;
1252   }
1253   return nullptr;
1254 }
