1291 /// \returns analysis of the Instructions in \p VL described in
1292 /// InstructionsState, the Opcode that we suppose the whole list
1293 /// could be vectorized even if its structure is diverse.
1294 static InstructionsState getSameOpcode(ArrayRef<Value *> VL,
1295                                        const TargetLibraryInfo &TLI) {
1296   // Make sure these are all Instructions.
1297   if (!all_of(VL, IsaPred<Instruction, PoisonValue>))
1298     return InstructionsState::invalid();
1299 
1300   auto *It = find_if(VL, IsaPred<Instruction>);
1301   if (It == VL.end())
1302     return InstructionsState::invalid();
1303 
1304   Instruction *MainOp = cast<Instruction>(*It);
1305   unsigned InstCnt = std::count_if(It, VL.end(), IsaPred<Instruction>);
1306   if ((VL.size() > 2 && !isa<PHINode>(MainOp) && InstCnt < VL.size() / 2) ||
1307       (VL.size() == 2 && InstCnt < 2))
1308     return InstructionsState::invalid();
1309 
1310   bool IsCastOp = isa<CastInst>(MainOp);
1311   bool IsBinOp = isa<BinaryOperator>(MainOp);
1312   bool IsCmpOp = isa<CmpInst>(MainOp);
1313   CmpInst::Predicate BasePred = IsCmpOp ? cast<CmpInst>(MainOp)->getPredicate()
1314                                         : CmpInst::BAD_ICMP_PREDICATE;
1315   Instruction *AltOp = MainOp;
1316   unsigned Opcode = MainOp->getOpcode();
1317   unsigned AltOpcode = Opcode;
1318 
1319   BinOpSameOpcodeHelper BinOpHelper(MainOp);
1320   bool SwappedPredsCompatible = IsCmpOp && [&]() {
1321     SetVector<unsigned> UniquePreds, UniqueNonSwappedPreds;
1322     UniquePreds.insert(BasePred);
1323     UniqueNonSwappedPreds.insert(BasePred);
1324     for (Value *V : VL) {
1325       auto *I = dyn_cast<CmpInst>(V);
1326       if (!I)
1327         return false;
1328       CmpInst::Predicate CurrentPred = I->getPredicate();
1329       CmpInst::Predicate SwappedCurrentPred =
1330           CmpInst::getSwappedPredicate(CurrentPred);
1331       UniqueNonSwappedPreds.insert(CurrentPred);
1332       if (!UniquePreds.contains(CurrentPred) &&
1333           !UniquePreds.contains(SwappedCurrentPred))
1334         UniquePreds.insert(CurrentPred);
1335     }
1336     // Total number of predicates > 2, but if consider swapped predicates
1337     // compatible only 2, consider swappable predicates as compatible opcodes,
1338     // not alternate.
1339     return UniqueNonSwappedPreds.size() > 2 && UniquePreds.size() == 2;
1340   }();
1341   // Check for one alternate opcode from another BinaryOperator.
1342   // TODO - generalize to support all operators (types, calls etc.).
1343   Intrinsic::ID BaseID = 0;
1344   SmallVector<VFInfo> BaseMappings;
1345   if (auto *CallBase = dyn_cast<CallInst>(MainOp)) {
1346     BaseID = getVectorIntrinsicIDForCall(CallBase, &TLI);
1347     BaseMappings = VFDatabase(*CallBase).getMappings(*CallBase);
1348     if (!isTriviallyVectorizable(BaseID) && BaseMappings.empty())
1349       return InstructionsState::invalid();
